function buildLightmap(surf: Surface, dest: Uint8Array, stride: number): void {
  const smax = (surf.extents[0] >> 4) + 1;
  const tmax = (surf.extents[1] >> 4) + 1;
  let bl = blocklights;
  for (let i = 0; i < tmax; i++, dest += stride) {
    for (let j = 0; j < smax; j++) {
      let t = bl[j] >> 7;
      if (t > 255) t = 255;
      dest[j] = t;
    }
    bl = bl.subarray(smax);
  }
}
